_Can you attach an example that shows the issue?  (Must be openly licensed, ideally in test_regress format.)_
`gy.v`
```verilog
// We get 8bit data in every clock
// Output back as 16bit data, updated every second clock

module gy (input         igy_clk,
           input [7:0]   igy_data_7_0,
           output [15:0] gy_outdata_15_0);

  //-------- Variables ------------------------------------------------------

  reg        ngy_inctr;
  reg [7:0]  ngy_inreg_7_0;
  reg [15:0] ngy_dinreg_15_0;

  reg        gy_inctr = 0;
  reg [7:0]  gy_inreg_7_0 = 0;
  reg [15:0] gy_dinreg_15_0 = 0;

  //-------------------------------------------------------------------------

  always @ * begin

    ngy_inctr = !gy_inctr;

    ngy_inreg_7_0 = igy_data_7_0;

    if (gy_inctr == 0)
      ngy_dinreg_15_0 = {gy_inreg_7_0,
                         igy_data_7_0};
    else
      ngy_dinreg_15_0 = gy_dinreg_15_0;

  end // always @ *


  always @ (posedge igy_clk) begin
    if (0) begin
      $write("\n");
      $write("igy_data_7_0        = %02x\n",  igy_data_7_0);
      $write("gy_inctr        = %01x",     gy_inctr);
      $write("   ngy_inctr        =     %01x\n", ngy_inctr);
      $write("gy_inreg_7_0    =   %02x",   gy_inreg_7_0);
      $write("   ngy_inreg_7_0    =   %02x\n",   ngy_inreg_7_0);
      $write("gy_dinreg_15_0  = %04x",     gy_dinreg_15_0);
      $write("   ngy_dinreg_15_0  = %04x\n",     ngy_dinreg_15_0);
      $write("\n");
    end
  end

  always @ (posedge igy_clk) begin
    gy_inctr        <= ngy_inctr;
    gy_inreg_7_0    <= ngy_inreg_7_0;
    gy_dinreg_15_0  <= ngy_dinreg_15_0;
  end

  assign gy_outdata_15_0 = gy_dinreg_15_0;

endmodule

```
`gy.cpp`
```c++
#include <verilated.h>
#include <iostream>
#include "Vgy.h"

Vgy* top;

int main(int argc, char **argv) {
  Verilated::commandArgs(argc, argv);
  unsigned int cnt = 0;

  top = new Vgy;

  while (!Verilated::gotFinish()) {
    top->igy_clk = 0;
    top->eval();

    top->igy_clk = 1;
    top->igy_data_7_0 = cnt;
    top->eval();
    printf("outdata = 0x%04x\n", top->gy_outdata_15_0);

    cnt++;
    if(cnt > 15){
      printf("DONE\n");
      break;
    }
  }
  top->final();
  delete top;
}
```
